const https = require('https');
const phone = $('📱 WhatsApp Trigger').item.json.messages[0].from;

// Llamamos al Edge Function que internamente usa service_role
// y limpia el teléfono igual que el middleware: split('@')[0].replace(/\D/g, '')
const url = `https://uhbmoslwucdhwrkgdleo.supabase.co/functions/v1/crear-factura-bot/api/reports/daily?user_phone=${encodeURIComponent(phone)}`;

return new Promise((resolve) => {
  const req = https.request(url, {
    method: 'GET',
    headers: {
      'apikey': 'sb_publishable_KiUko3HqeUGDFYCoTDEpOw_5ERJ50Ll',
      'Authorization': 'Bearer sb_publishable_KiUko3HqeUGDFYCoTDEpOw_5ERJ50Ll'
    }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => data += chunk);
    res.on('end', () => {
      try {
        const statusCode = res.statusCode;
        // 200 = usuario registrado, 401 = no registrado / no encontrado
        const isRegistered = statusCode === 200;
        let parsed = {};
        try { parsed = JSON.parse(data); } catch(_) {}
        resolve([{ json: { isRegistered, phone, statusCode, debug: parsed } }]);
      } catch(e) {
        resolve([{ json: { isRegistered: false, phone, error: e.message } }]);
      }
    });
  });
  req.on('error', (e) => {
    resolve([{ json: { isRegistered: false, phone, error: e.message } }]);
  });
  req.end();
});

